const data = JSON.parse($input.first().json.stdout || '{}');
const needsNotification = data.IsRecentBoot && !data.AlreadyNotified;

return [{
  json: {
    ...data,
    needsNotification: needsNotification
  }
}];

const bootData = $('Evaluate Boot Status').first().json;
const healthRaw = $input.first().json.stdout || '{}';
let health;
try { health = JSON.parse(healthRaw); } catch { health = { error: 'parse failed' }; }

const emailBody = `Rudy is back online.

Boot time: ${bootData.BootTime}
Uptime: ${bootData.UptimeMinutes} minutes

Post-boot health check:
- Services: ${health.Services || 'unknown'}
- RAM Free: ${health.RAM_Free_GB || '?'} GB
- Disk Free: ${health.Disk_Free_GB || '?'} GB

All automated workflows have resumed. Monitoring is active.`;

return [{ json: { emailBody: emailBody, bootTime: bootData.BootTime, markerFile: bootData.MarkerFile } }];
